### 5. DIALOG PATTERNS

**Create Policy Dialog:** `/Users/marcus/conductor/workspaces/brain-v1/lahore-v1/app/src/client/components/policy/CreatePolicyDialog.tsx`

**Pattern:**
- Form state: `useState` for all fields
- Errors object: separate state, per-field validation
- `updateField()` callback: type-safe setter with error clearing on change
- Validation: pure function `validateForm()` returns all errors
- Request body: pure function `buildRequestBody()` from form state
- On success: reset form, close dialog, navigate to detail page

```typescript
type CreatePolicyDialogProps = {
  open: boolean;
  onClose: () => void;
};

export function CreatePolicyDialog({ open, onClose }: CreatePolicyDialogProps) {
  const [form, setForm] = useState<PolicyFormState>(createInitialFormState);
  const [errors, setErrors] = useState<FormErrors>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const updateField = useCallback(
    <K extends keyof PolicyFormState>(field: K, value: PolicyFormState[K]) => {
      setForm((prev) => ({ ...prev, [field]: value }));
      setErrors((prev) => {
        const next = { ...prev };
        if (field === "title") delete next.title;
        // ... clear related errors
        delete next.submit;
        return next;
      });
    },
    [],
  );

  const handleSubmit = useCallback(async () => {
    const validationErrors = validateForm(form);
    if (hasErrors(validationErrors)) { setErrors(validationErrors); return; }

    setIsSubmitting(true);
    setErrors({});

    try {
      const url = `/api/workspaces/${workspaceId}/policies`;
      const response = await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(buildRequestBody(form)),
      });

      if (!response.ok) {
        const text = await response.text();
        const message = tryParseJsonError(text);
        setErrors({ submit: message || "Failed to create policy" });
        return;
      }

      const data = (await response.json()) as { policy_id: string };
      setForm(createInitialFormState());
      setErrors({});
      onClose();
      void navigate({ to: "/policies/$policyId", params: { policyId: data.policy_id } });
    } catch (err) {
      setErrors({ submit: err instanceof Error ? err.message : "Failed to create policy" });
    } finally {
      setIsSubmitting(false);
    }
  }, [form, workspaceId, onClose, navigate]);

  return (
    <Dialog open={open} onOpenChange={(o) => { if (!o) handleClose(); }}>
      <DialogContent className="sm:max-w-lg">
        <DialogHeader>
          <DialogTitle>Create Policy</DialogTitle>
        </DialogHeader>

        {/* Form fields with error display */}
        <div className="flex flex-col gap-3">
          {errors.submit && <p className="text-sm text-destructive">{errors.submit}</p>}

          {/* Field groups with labels, inputs, error messages */}
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={handleClose} disabled={isSubmitting}>Cancel</Button>
          <Button onClick={handleSubmit} disabled={isSubmitting}>Create Policy</Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
```

**Two-Phase Dialog Pattern (Learning Create):**

Learning dialog has a "collision detection" phase:
1. User enters text → form phase
2. On submit: call `suggest_work_items` tool to detect duplicates
3. If collisions found: show collisions phase with merge/create options
4. User confirms → API call

This is reusable for Tool Registry if tool registration needs duplication checks.

