export function LearningList({ learnings, isLoading, onAction }: LearningListProps) {
  const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());

  const handleToggle = useCallback((learningId: string) => {
    setExpandedIds((prev) => {
      const next = new Set(prev);
      next.has(learningId) ? next.delete(learningId) : next.add(learningId);
      return next;
    });
  }, []);

  if (isLoading) return undefined;
  if (learnings.length === 0) return <EmptyState />;

  return (
    <div className="flex flex-col gap-3">
      {learnings.map((learning) => (
        <LearningCard
          key={learning.id}
          learning={learning}
          isExpanded={expandedIds.has(learning.id)}
          onToggle={() => handleToggle(learning.id)}
          onAction={onAction}
        />
      ))}
    </div>
  );
}
