  1→import { useState } from "react";
  2→import { Outlet, createRootRoute, createRoute, createRouter, redirect, useNavigate } from "@tanstack/react-router";
  3→import { authClient } from "./lib/auth-client";
  4→import { WorkspaceGuard } from "./components/layout/WorkspaceGuard";
  5→import { WorkspaceSidebar } from "./components/layout/WorkspaceSidebar";
  6→import { SearchOverlay } from "./components/search/SearchOverlay";
  7→import { useWorkspace } from "./hooks/use-workspace";
  8→import { useWorkspaceState } from "./stores/workspace-state";
  9→import { ChatPage } from "./routes/chat-page";
 10→import { GraphPage } from "./routes/graph-page";
 11→import { HomePage } from "./routes/home-page";
 12→import { ReviewPage } from "./routes/review-page";
 13→import { LearningsPage } from "./routes/learnings-page";
 14→import { PoliciesPage } from "./components/policy/PoliciesPage";
 15→import { PolicyDetailPage } from "./components/policy/PolicyDetailPage";
 16→import { SignInPage } from "./routes/sign-in-page";
 17→import { ConsentPage } from "./routes/consent-page";
 18→import { Button } from "./components/ui/button";
 19→import { Badge } from "./components/ui/badge";
 20→import { Search } from "lucide-react";
 21→
 22→function AppShell() {
 23→  const workspace = useWorkspace();
 24→  const sidebar = useWorkspaceState((s) => s.sidebar);
 25→  const sidebarHandlers = useWorkspaceState((s) => s.sidebarHandlers);
 26→  const workspaceName = useWorkspaceState((s) => s.workspaceName);
 27→  const onboardingState = useWorkspaceState((s) => s.onboardingState);
 28→  const navigate = useNavigate();
 29→  const [searchOpen, setSearchOpen] = useState(false);
 30→
 31→  function handleNewConversation() {
 32→    if (sidebarHandlers) {
 33→      sidebarHandlers.onNewConversation();
 34→    }
 35→    void navigate({ to: "/chat" });
 36→  }
 37→
 38→  function handleSelectConversation(conversationId: string) {
 39→    if (sidebarHandlers) {
 40→      sidebarHandlers.onSelectConversation(conversationId);
 41→    }
 42→    void navigate({ to: "/chat/$conversationId", params: { conversationId } });
 43→  }
 44→
 45→  return (
 46→    <WorkspaceGuard
 47→      isReady={workspace.isReady}
 48→      isBootstrapping={workspace.isBootstrapping}
 49→      isCreatingWorkspace={workspace.isCreatingWorkspace}
 50→      canCreateWorkspace={workspace.canCreateWorkspace}
 51→      createWorkspaceName={workspace.createWorkspaceName}
 52→      createWorkspaceDescription={workspace.createWorkspaceDescription}
 53→      createWorkspaceRepoPath={workspace.createWorkspaceRepoPath}
 54→      errorMessage={workspace.errorMessage}
 55→      setCreateWorkspaceName={workspace.setCreateWorkspaceName}
 56→      setCreateWorkspaceDescription={workspace.setCreateWorkspaceDescription}
 57→      setCreateWorkspaceRepoPath={workspace.setCreateWorkspaceRepoPath}
 58→      onCreateWorkspace={workspace.onCreateWorkspace}
 59→    >
 60→      <div className="flex h-screen overflow-hidden bg-background text-foreground">
 61→        <WorkspaceSidebar
 62→          sidebar={sidebar}
 63→          activeConversationId={sidebarHandlers?.activeConversationId}
