  1→/**
  2→ * Credential provider domain types.
  3→ *
  4→ * Auth method variants: oauth2, api_key, bearer, basic.
  5→ * Encrypted fields use _encrypted suffix (ADR-068).
  6→ */
  7→import type { RecordId } from "surrealdb";
  8→
  9→export type AuthMethod = "oauth2" | "api_key" | "bearer" | "basic";
 10→
 11→/**
 12→ * Input payload for creating a credential provider via API.
 13→ * client_secret is plaintext here -- encrypted before storage.
 14→ */
 15→export type CreateProviderInput = {
 16→  name: string;
 17→  display_name: string;
 18→  auth_method: AuthMethod;
 19→  authorization_url?: string;
 20→  token_url?: string;
 21→  client_id?: string;
 22→  client_secret?: string;
 23→  scopes?: string[];
 24→  api_key_header?: string;
 25→};
 26→
 27→/**
 28→ * SurrealDB record shape for credential_provider.
 29→ */
 30→export type CredentialProviderRecord = {
 31→  id: RecordId<"credential_provider", string>;
 32→  name: string;
 33→  display_name: string;
 34→  auth_method: AuthMethod;
 35→  workspace: RecordId<"workspace", string>;
 36→  authorization_url?: string;
 37→  token_url?: string;
 38→  client_id?: string;
 39→  client_secret_encrypted?: string;
 40→  scopes?: string[];
 41→  api_key_header?: string;
 42→  created_at: Date;
 43→};
 44→
 45→/**
 46→ * Status of a connected account.
 47→ */
 48→export type AccountStatus = "active" | "revoked" | "expired";
 49→
 50→/**
 51→ * Input payload for connecting an account via static credentials (API key, basic, bearer).
 52→ * OAuth2 connections are initiated via redirect flow -- no credentials in this payload.
 53→ */
 54→export type ConnectAccountInput = {
 55→  api_key?: string;
 56→  bearer_token?: string;
 57→  basic_username?: string;
 58→  basic_password?: string;
 59→};
 60→
 61→/**
 62→ * SurrealDB record shape for connected_account.
 63→ */
 64→export type ConnectedAccountRecord = {
 65→  id: RecordId<"connected_account", string>;
 66→  identity: RecordId<"identity", string>;
 67→  provider: RecordId<"credential_provider", string>;
 68→  workspace: RecordId<"workspace", string>;
 69→  status: AccountStatus;
 70→  access_token_encrypted?: string;
 71→  refresh_token_encrypted?: string;
 72→  token_expires_at?: Date;
 73→  api_key_encrypted?: string;
 74→  basic_username?: string;
 75→  basic_password_encrypted?: string;
 76→  bearer_token_encrypted?: string;
 77→  scopes?: string[];
 78→  connected_at: Date;
 79→  updated_at: Date;
 80→};
 81→
 82→/**
 83→ * API response shape for connected accounts -- never contains plaintext secrets.
 84→ */
 85→export type ConnectedAccountApiResponse = {
 86→  id: string;
 87→  provider_id: string;
 88→  status: AccountStatus;
 89→  has_api_key: boolean;
 90→  has_bearer_token: boolean;
 91→  has_basic_credentials: boolean;
 92→  has_access_token: boolean;
 93→  connected_at: string;
 94→};
 95→
 96→/**
 97→ * OAuth2 initiation response -- returned when connecting to an oauth2 provider.
 98→ */
 99→export type OAuth2InitiationResponse = {
100→  redirect_url: string;
101→  state: string;
102→};
103→
104→/**
105→ * API response shape -- never contains plaintext secrets.
106→ */
107→export type ProviderApiResponse = {
108→  id: string;
109→  name: string;
110→  display_name: string;
111→  auth_method: AuthMethod;
112→  authorization_url?: string;
113→  token_url?: string;
114→  client_id?: string;
115→  has_client_secret: boolean;
116→  scopes?: string[];
117→  api_key_header?: string;
118→  created_at: string;
119→};
120→

  1→/**
  2→ * HTTP routes for credential provider CRUD and account connection.
  3→ *
  4→ * POST /api/workspaces/:workspaceId/providers -- create provider
  5→ * GET  /api/workspaces/:workspaceId/providers -- list providers
  6→ * POST /api/workspaces/:workspaceId/accounts/connect/:providerId -- connect account
  7→ * GET  /api/workspaces/:workspaceId/accounts -- list connected accounts
  8→ *
  9→ * Secrets encrypted before storage, never returned as plaintext.
 10→ */
 11→import { RecordId } from "surrealdb";
 12→import { HttpError } from "../http/errors";
 13→import { jsonError, jsonResponse } from "../http/response";
 14→import type { ServerDependencies } from "../runtime/types";
 15→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 16→import {
 17→  providerNameExists,
 18→  createProvider,
 19→  listProviders,
 20→  getProviderById,
 21→  activeAccountExists,
 22→  createConnectedAccount,
 23→  listConnectedAccounts,
 24→  revokeConnectedAccount,
 25→} from "./queries";
 26→import { encryptSecret } from "./encryption";
 27→import { buildAuthorizationUrl, storeOAuthState } from "./oauth-flow";
 28→import type {
 29→  CreateProviderInput,
 30→  CredentialProviderRecord,
 31→  ProviderApiResponse,
 32→  ConnectedAccountRecord,
 33→  ConnectedAccountApiResponse,
 34→  ConnectAccountInput,
 35→} from "./types";
 36→import { log } from "../telemetry/logger";
 37→
 38→const VALID_AUTH_METHODS = ["oauth2", "api_key", "bearer", "basic"] as const;
 39→
 40→// ---------------------------------------------------------------------------
 41→// Response mapping -- strip encrypted fields, expose has_client_secret flag
 42→// ---------------------------------------------------------------------------
 43→
 44→function toApiResponse(record: CredentialProviderRecord): ProviderApiResponse {
 45→  const response: ProviderApiResponse = {
 46→    id: record.id.id as string,
 47→    name: record.name,
 48→    display_name: record.display_name,
 49→    auth_method: record.auth_method,
 50→    has_client_secret: !!record.client_secret_encrypted,
 51→    created_at: record.created_at instanceof Date
 52→      ? record.created_at.toISOString()
 53→      : String(record.created_at),
 54→  };
 55→
 56→  if (record.authorization_url) response.authorization_url = record.authorization_url;
 57→  if (record.token_url) response.token_url = record.token_url;
 58→  if (record.client_id) response.client_id = record.client_id;
 59→  if (record.scopes) response.scopes = record.scopes;
 60→  if (record.api_key_header) response.api_key_header = record.api_key_header;
 61→
 62→  return response;
 63→}
 64→
 65→// ---------------------------------------------------------------------------
 66→// Route handlers
 67→// ---------------------------------------------------------------------------
 68→
 69→export function createProviderRouteHandlers(deps: ServerDependencies) {
 70→  const encryptionKey = deps.config.toolEncryptionKey;
 71→
 72→  async function handleCreate(workspaceId: string, request: Request): Promise<Response> {
 73→    let workspaceRecord;
 74→    try {
 75→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 76→    } catch (error) {
 77→      if (error instanceof HttpError) {
 78→        return jsonError(error.message, error.status);
 79→      }
 80→      log.error("provider.create", "Failed to resolve workspace", error, { workspaceId });
 81→      return jsonError("internal error", 500);
 82→    }
 83→
 84→    let body: CreateProviderInput;
 85→    try {
 86→      body = await request.json() as CreateProviderInput;
 87→    } catch {
 88→      return jsonError("invalid JSON body", 400);
 89→    }
 90→
 91→    // Validate required fields
 92→    if (!body.name || typeof body.name !== "string") {
 93→      return jsonError("name is required", 400);
 94→    }
 95→    if (!body.display_name || typeof body.display_name !== "string") {
 96→      return jsonError("display_name is required", 400);
 97→    }
 98→    if (!body.auth_method || !VALID_AUTH_METHODS.includes(body.auth_method as any)) {
 99→      return jsonError(`auth_method must be one of: ${VALID_AUTH_METHODS.join(", ")}`, 400);
100→    }
101→
102→    // Check duplicate name within workspace
103→    const exists = await providerNameExists(deps.surreal, workspaceRecord, body.name);
104→    if (exists) {
105→      return jsonError(`provider with name "${body.name}" already exists in workspace`, 409);
106→    }
107→
108→    // Build content, encrypting secret if present
109→    const content: Record<string, unknown> = {
110→      name: body.name,
111→      display_name: body.display_name,
112→      auth_method: body.auth_method,
113→    };
114→
115→    if (body.authorization_url) content.authorization_url = body.authorization_url;
116→    if (body.token_url) content.token_url = body.token_url;
117→    if (body.client_id) content.client_id = body.client_id;
118→    if (body.scopes) content.scopes = body.scopes;
119→    if (body.api_key_header) content.api_key_header = body.api_key_header;
120→
121→    if (body.client_secret && encryptionKey) {
122→      content.client_secret_encrypted = encryptSecret(body.client_secret, encryptionKey);
123→    }
124→
125→    const record = await createProvider(deps.surreal, workspaceRecord, content);
126→    return jsonResponse(toApiResponse(record), 201);
127→  }
128→
129→  async function handleList(workspaceId: string, _request: Request): Promise<Response> {
130→    let workspaceRecord;
131→    try {
132→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
133→    } catch (error) {
134→      if (error instanceof HttpError) {
135→        return jsonError(error.message, error.status);
136→      }
137→      log.error("provider.list", "Failed to resolve workspace", error, { workspaceId });
138→      return jsonError("internal error", 500);
139→    }
140→
141→    const records = await listProviders(deps.surreal, workspaceRecord);
142→    const providers = records.map(toApiResponse);
143→    return jsonResponse({ providers }, 200);
144→  }
145→
146→  return { handleCreate, handleList };
147→}
