168→// ---------------------------------------------------------------------------
169→// Account connection route handlers
170→// ---------------------------------------------------------------------------
171→
172→export function createAccountRouteHandlers(deps: ServerDependencies) {
173→  const encryptionKey = deps.config.toolEncryptionKey;
174→
175→  /**
176→   * POST /api/workspaces/:workspaceId/accounts/connect/:providerId
177→   *
178→   * For api_key/bearer/basic: encrypts credentials and creates connected_account.
179→   * For oauth2: returns redirect URL for user to authorize at provider.
180→   */
181→  async function handleConnect(
182→    workspaceId: string,
183→    providerId: string,
184→    request: Request,
185→  ): Promise<Response> {
186→    let workspaceRecord;
187→    try {
188→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
189→    } catch (error) {
190→      if (error instanceof HttpError) {
191→        return jsonError(error.message, error.status);
192→      }
193→      log.error("account.connect", "Failed to resolve workspace", error, { workspaceId });
194→      return jsonError("internal error", 500);
195→    }
196→
197→    // Look up the credential provider
198→    const provider = await getProviderById(deps.surreal, providerId);
199→    if (!provider) {
200→      return jsonError("credential provider not found", 404);
201→    }
202→
203→    // Extract identity from request headers (set by DPoP middleware)
204→    const identityId = request.headers.get("X-Brain-Identity");
205→    if (!identityId) {
206→      return jsonError("identity required", 401);
207→    }
208→
209→    const identityRecord = new RecordId("identity", identityId);
210→    const providerRecord = new RecordId("credential_provider", providerId);
211→
212→    // Check for existing active account
213→    const alreadyExists = await activeAccountExists(deps.surreal, identityRecord, providerRecord);
214→    if (alreadyExists) {
215→      return jsonError("active account already exists for this provider", 409);
216→    }
217→
218→    // OAuth2: return redirect URL
219→    if (provider.auth_method === "oauth2") {
220→      const state = crypto.randomUUID();
221→      const baseUrl = request.headers.get("Origin") ?? `${new URL(request.url).origin}`;
222→      const redirectUri = `${baseUrl}/api/workspaces/${workspaceId}/accounts/oauth2/callback`;
223→
224→      storeOAuthState(state, {
225→        providerId,
226→        identityId,
227→        workspaceId,
228→        createdAt: Date.now(),
229→      });
230→
231→      const redirectUrl = buildAuthorizationUrl(provider, redirectUri, state);
232→      return jsonResponse({ redirect_url: redirectUrl, state }, 200);
233→    }
234→
235→    // Static credentials: parse body and encrypt
236→    let body: ConnectAccountInput;
237→    try {
238→      body = await request.json() as ConnectAccountInput;
239→    } catch {
240→      return jsonError("invalid JSON body", 400);
241→    }
242→
243→    if (!encryptionKey) {
244→      log.error("account.connect", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
245→      return jsonError("encryption not configured", 500);
246→    }
247→
248→    const content: Record<string, unknown> = {
249→      identity: identityRecord,
250→      provider: providerRecord,
251→      workspace: workspaceRecord,
252→      status: "active",
253→    };
254→
255→    switch (provider.auth_method) {
256→      case "api_key": {
257→        if (!body.api_key) {
258→          return jsonError("api_key is required for api_key auth method", 400);
259→        }
260→        content.api_key_encrypted = encryptSecret(body.api_key, encryptionKey);
261→        break;
262→      }
263→      case "bearer": {
264→        if (!body.bearer_token) {
265→          return jsonError("bearer_token is required for bearer auth method", 400);
266→        }
267→        content.bearer_token_encrypted = encryptSecret(body.bearer_token, encryptionKey);
268→        break;
269→      }
270→      case "basic": {
271→        if (!body.basic_username || !body.basic_password) {
272→          return jsonError("basic_username and basic_password are required for basic auth method", 400);
273→        }
274→        content.basic_username = body.basic_username;
275→        content.basic_password_encrypted = encryptSecret(body.basic_password, encryptionKey);
276→        break;
277→      }
278→      default:
279→        return jsonError(`unsupported auth method: ${provider.auth_method}`, 400);
280→    }
281→
282→    const record = await createConnectedAccount(deps.surreal, content);
283→    return jsonResponse(toAccountApiResponse(record), 201);
284→  }
285→
286→  /**
287→   * GET /api/workspaces/:workspaceId/accounts
288→   *
289→   * List connected accounts for the authenticated identity.
290→   */
291→  async function handleListAccounts(
292→    workspaceId: string,
293→    request: Request,
294→  ): Promise<Response> {
295→    let workspaceRecord;
296→    try {
297→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
298→    } catch (error) {
299→      if (error instanceof HttpError) {
300→        return jsonError(error.message, error.status);
301→      }
302→      log.error("account.list", "Failed to resolve workspace", error, { workspaceId });
303→      return jsonError("internal error", 500);
304→    }
305→
306→    const identityId = request.headers.get("X-Brain-Identity");
307→    if (!identityId) {
308→      return jsonError("identity required", 401);
309→    }
310→
311→    const identityRecord = new RecordId("identity", identityId);
312→    const records = await listConnectedAccounts(deps.surreal, identityRecord, workspaceRecord);
313→    const accounts = records.map(toAccountApiResponse);
314→    return jsonResponse({ accounts }, 200);
315→  }
316→
317→  /**
318→   * DELETE /api/workspaces/:workspaceId/accounts/:accountId
319→   *
320→   * Revoke a connected account: sets status to "revoked" and hard-deletes
321→   * all encrypted credential fields. Idempotent.
322→   */
323→  async function handleRevoke(
324→    workspaceId: string,
325→    accountId: string,
326→    request: Request,
327→  ): Promise<Response> {
328→    let workspaceRecord;
329→    try {
330→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
331→    } catch (error) {
332→      if (error instanceof HttpError) {
333→        return jsonError(error.message, error.status);
334→      }
335→      log.error("account.revoke", "Failed to resolve workspace", error, { workspaceId });
336→      return jsonError("internal error", 500);
337→    }
338→
339→    const identityId = request.headers.get("X-Brain-Identity");
340→    if (!identityId) {
341→      return jsonError("identity required", 401);
342→    }
343→
344→    const identityRecord = new RecordId("identity", identityId);
345→    const accountRecord = new RecordId("connected_account", accountId);
346→
347→    const updated = await revokeConnectedAccount(
348→      deps.surreal,
349→      accountRecord,
350→      identityRecord,
351→      workspaceRecord,
352→    );
353→
354→    if (!updated) {
355→      return jsonError("connected account not found", 404);
356→    }
357→
358→    return jsonResponse({ status: "revoked" }, 200);
359→  }
360→
361→  return { handleConnect, handleListAccounts, handleRevoke };
362→}
