 1→/**
 2→ * AES-256-GCM encryption adapter for credential secrets.
 3→ *
 4→ * Each encrypted value = base64(IV || ciphertext || authTag).
 5→ * 12-byte random IV per encryption. 16-byte auth tag.
 6→ * Key must be a 256-bit (32-byte) hex string.
 7→ *
 8→ * Pure functions with no side effects beyond crypto randomness.
 9→ * ADR-066, ADR-068.
10→ */
11→import { createCipheriv, createDecipheriv, randomBytes } from "node:crypto";
12→
13→const ALGORITHM = "aes-256-gcm";
14→const IV_LENGTH = 12;
15→const AUTH_TAG_LENGTH = 16;
16→
17→/**
18→ * Encrypt plaintext using AES-256-GCM.
19→ * Returns base64-encoded string containing IV + ciphertext + authTag.
20→ */
21→export function encryptSecret(plaintext: string, keyHex: string): string {
22→  const key = Buffer.from(keyHex, "hex");
23→  if (key.length !== 32) {
24→    throw new Error("Encryption key must be 256 bits (64 hex characters)");
25→  }
26→
27→  const iv = randomBytes(IV_LENGTH);
28→  const cipher = createCipheriv(ALGORITHM, key, iv, { authTagLength: AUTH_TAG_LENGTH });
29→
30→  const encrypted = Buffer.concat([
31→    cipher.update(plaintext, "utf8"),
32→    cipher.final(),
33→  ]);
34→
35→  const authTag = cipher.getAuthTag();
36→
37→  // Pack: IV || ciphertext || authTag
38→  const packed = Buffer.concat([iv, encrypted, authTag]);
39→  return packed.toString("base64");
40→}
41→
42→/**
43→ * Decrypt a base64-encoded AES-256-GCM ciphertext.
44→ * Input format: base64(IV || ciphertext || authTag).
45→ */
46→export function decryptSecret(ciphertextBase64: string, keyHex: string): string {
47→  const key = Buffer.from(keyHex, "hex");
48→  if (key.length !== 32) {
49→    throw new Error("Encryption key must be 256 bits (64 hex characters)");
50→  }
51→
52→  const packed = Buffer.from(ciphertextBase64, "base64");
53→
54→  if (packed.length < IV_LENGTH + AUTH_TAG_LENGTH) {
55→    throw new Error("Ciphertext too short to contain IV and auth tag");
56→  }
57→
58→  const iv = packed.subarray(0, IV_LENGTH);
59→  const authTag = packed.subarray(packed.length - AUTH_TAG_LENGTH);
60→  const ciphertext = packed.subarray(IV_LENGTH, packed.length - AUTH_TAG_LENGTH);
61→
62→  const decipher = createDecipheriv(ALGORITHM, key, iv, { authTagLength: AUTH_TAG_LENGTH });
63→  decipher.setAuthTag(authTag);
64→
65→  const decrypted = Buffer.concat([
66→    decipher.update(ciphertext),
67→    decipher.final(),
68→  ]);
69→
70→  return decrypted.toString("utf8");
71→}
