  1→/**
  2→ * OAuth2 authorization flow helpers for credential providers.
  3→ *
  4→ * Pure functions for building authorization URLs and exchanging codes for tokens.
  5→ * State management uses an in-memory map (sufficient for walking skeleton;
  6→ * production should use short-lived DB records).
  7→ *
  8→ * ADR-066, ADR-068.
  9→ */
 10→
 11→import type { CredentialProviderRecord } from "./types";
 12→
 13→// ---------------------------------------------------------------------------
 14→// State Store -- in-memory map keyed by state parameter
 15→// ---------------------------------------------------------------------------
 16→
 17→export type OAuthStateEntry = {
 18→  providerId: string;
 19→  identityId: string;
 20→  workspaceId: string;
 21→  createdAt: number;
 22→};
 23→
 24→const pendingStates = new Map<string, OAuthStateEntry>();
 25→
 26→/** TTL for state entries: 10 minutes */
 27→const STATE_TTL_MS = 10 * 60 * 1000;
 28→
 29→/**
 30→ * Store a state parameter for later verification during callback.
 31→ */
 32→export function storeOAuthState(state: string, entry: OAuthStateEntry): void {
 33→  pendingStates.set(state, entry);
 34→}
 35→
 36→/**
 37→ * Retrieve and consume a state entry. Returns undefined if not found or expired.
 38→ */
 39→export function consumeOAuthState(state: string): OAuthStateEntry | undefined {
 40→  const entry = pendingStates.get(state);
 41→  if (!entry) return undefined;
 42→
 43→  pendingStates.delete(state);
 44→
 45→  const elapsed = Date.now() - entry.createdAt;
 46→  if (elapsed > STATE_TTL_MS) return undefined;
 47→
 48→  return entry;
 49→}
 50→
 51→// ---------------------------------------------------------------------------
 52→// Authorization URL Builder
 53→// ---------------------------------------------------------------------------
 54→
 55→/**
 56→ * Build the OAuth2 authorization URL for a provider.
 57→ * Returns the full URL with client_id, redirect_uri, scopes, state, and response_type=code.
 58→ */
 59→export function buildAuthorizationUrl(
 60→  provider: CredentialProviderRecord,
 61→  redirectUri: string,
 62→  state: string,
 63→): string {
 64→  if (!provider.authorization_url) {
 65→    throw new Error("Provider missing authorization_url for OAuth2 flow");
 66→  }
 67→  if (!provider.client_id) {
 68→    throw new Error("Provider missing client_id for OAuth2 flow");
 69→  }
 70→
 71→  const url = new URL(provider.authorization_url);
 72→  url.searchParams.set("client_id", provider.client_id);
 73→  url.searchParams.set("redirect_uri", redirectUri);
 74→  url.searchParams.set("response_type", "code");
 75→  url.searchParams.set("state", state);
 76→
 77→  if (provider.scopes && provider.scopes.length > 0) {
 78→    url.searchParams.set("scope", provider.scopes.join(" "));
 79→  }
 80→
 81→  return url.toString();
 82→}
 83→
 84→// ---------------------------------------------------------------------------
 85→// Token Exchange
 86→// ---------------------------------------------------------------------------
 87→
 88→export type TokenExchangeResult = {
 89→  access_token: string;
 90→  refresh_token?: string;
 91→  expires_in?: number;
 92→  scope?: string;
 93→};
 94→
 95→/**
 96→ * Exchange an authorization code for tokens at the provider's token endpoint.
 97→ * Sends client_id and client_secret via POST body (application/x-www-form-urlencoded).
 98→ */
 99→export async function exchangeCodeForTokens(
100→  provider: CredentialProviderRecord,
101→  code: string,
102→  redirectUri: string,
103→  clientSecret: string,
104→): Promise<TokenExchangeResult> {
105→  if (!provider.token_url) {
106→    throw new Error("Provider missing token_url for OAuth2 token exchange");
107→  }
108→  if (!provider.client_id) {
109→    throw new Error("Provider missing client_id for OAuth2 token exchange");
110→  }
111→
112→  const body = new URLSearchParams({
113→    grant_type: "authorization_code",
114→    code,
115→    redirect_uri: redirectUri,
116→    client_id: provider.client_id,
117→    client_secret: clientSecret,
118→  });
119→
120→  const response = await fetch(provider.token_url, {
121→    method: "POST",
122→    headers: { "Content-Type": "application/x-www-form-urlencoded", Accept: "application/json" },
123→    body: body.toString(),
124→  });
125→
126→  if (!response.ok) {
127→    const text = await response.text();
128→    throw new Error(`Token exchange failed (${response.status}): ${text}`);
129→  }
130→
131→  const data = await response.json() as TokenExchangeResult;
132→  return data;
133→}
