11→type UseLearningsReturn = {
12→  learnings: LearningSummary[];
13→  isLoading: boolean;
14→  error?: string;
15→  filters: LearningFilters;
16→  setFilters: (filters: LearningFilters) => void;
17→  refresh: () => void;
18→};
19→
20→/** Pure function: builds the API URL for fetching learnings with optional filters. */
21→export function buildLearningsUrl(workspaceId: string, filters: LearningFilters): string {
22→  const base = `/api/workspaces/${encodeURIComponent(workspaceId)}/learnings`;
23→  const params = new URLSearchParams();
24→
25→  if (filters.status) params.set("status", filters.status);
26→  if (filters.type) params.set("type", filters.type);
27→  if (filters.agent) params.set("agent", filters.agent);
28→
29→  const query = params.toString();
30→  return query ? `${base}?${query}` : base;
31→}
32→
33→export function useLearnings(): UseLearningsReturn {
34→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
35→  const [learnings, setLearnings] = useState<LearningSummary[]>([]);
36→  const [isLoading, setIsLoading] = useState(false);
37→  const [error, setError] = useState<string | undefined>();
38→  const [filters, setFilters] = useState<LearningFilters>({});
39→
40→  const fetchLearnings = useCallback(async () => {
41→    if (!workspaceId) return;
42→
43→    setIsLoading(true);
44→    setError(undefined);
45→
46→    try {
47→      const url = buildLearningsUrl(workspaceId, filters);
48→      const response = await fetch(url);
49→      if (!response.ok) {
50→        const body = await response.text();
51→        throw new Error(body);
52→      }
53→      const data = (await response.json()) as { learnings: LearningSummary[] };
54→      setLearnings(data.learnings);
55→    } catch (err) {
56→      setError(err instanceof Error ? err.message : "Failed to load learnings");
57→    } finally {
58→      setIsLoading(false);
59→    }
60→  }, [workspaceId, filters]);
61→
62→  useEffect(() => {
63→    if (!workspaceId) return;
64→    void fetchLearnings();
65→  }, [workspaceId, filters, fetchLearnings]);
66→
67→  const refresh = useCallback(() => {
68→    void fetchLearnings();
69→  }, [fetchLearnings]);
70→
71→  return { learnings, isLoading, error, filters, setFilters, refresh };
72→}
