 26→  description: string;
 27→  agentRole: string;
 28→  humanVetoRequired: boolean;
 29→  maxTtl: string;
 30→  rules: RuleEntry[];
 31→};
 32→
 33→type FormErrors = {
 34→  title?: string;
 35→  description?: string;
 36→  rules?: string;
 37→  submit?: string;
 38→};
 39→
 40→// ---------------------------------------------------------------------------
 41→// Pure form helpers
 42→// ---------------------------------------------------------------------------
 43→
 44→function createInitialFormState(): PolicyFormState {
 45→  return {
 46→    title: "",
 47→    description: "",
 48→    agentRole: "",
 49→    humanVetoRequired: false,
 50→    maxTtl: "",
 51→    rules: [createEmptyRule()],
 52→  };
 53→}
 54→
 55→function validateForm(state: PolicyFormState): FormErrors {
 56→  const errors: FormErrors = {};
 57→  if (state.title.trim() === "") errors.title = "Title is required";
 58→  if (state.description.trim() === "") errors.description = "Description is required";
 59→  if (state.rules.length === 0) {
 60→    errors.rules = "At least one rule is required";
 61→  } else {
 62→    const hasEmptyField = state.rules.some((r) => r.field.trim() === "");
 63→    if (hasEmptyField) errors.rules = "All rules must have a non-empty field";
 64→  }
 65→  return errors;
 66→}
 67→
 68→function hasErrors(errors: FormErrors): boolean {
 69→  return Object.keys(errors).length > 0;
 70→}
 71→
 72→function buildRequestBody(state: PolicyFormState) {
 73→  const body: Record<string, unknown> = {
 74→    title: state.title.trim(),
 75→    description: state.description.trim(),
 76→    rules: state.rules.map(ruleEntryToApiRule),
 77→  };
 78→  if (state.agentRole.trim()) body.selector = { agent_role: state.agentRole.trim() };
 79→  if (state.humanVetoRequired) body.human_veto_required = true;
 80→  if (state.maxTtl.trim()) body.max_ttl = state.maxTtl.trim();
 81→  return body;
 82→}
