 93→export function CreatePolicyDialog({ open, onClose }: CreatePolicyDialogProps) {
 94→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
 95→  const navigate = useNavigate();
 96→
 97→  const [form, setForm] = useState<PolicyFormState>(createInitialFormState);
 98→  const [errors, setErrors] = useState<FormErrors>({});
 99→  const [isSubmitting, setIsSubmitting] = useState(false);
100→
101→  const updateField = useCallback(
102→    <K extends keyof PolicyFormState>(field: K, value: PolicyFormState[K]) => {
103→      setForm((prev) => ({ ...prev, [field]: value }));
104→      setErrors((prev) => {
105→        const next = { ...prev };
106→        if (field === "title") delete next.title;
107→        if (field === "description") delete next.description;
108→        if (field === "rules") delete next.rules;
109→        delete next.submit;
110→        return next;
111→      });
112→    },
113→    [],
114→  );
115→
116→  const handleRulesChange = useCallback(
117→    (rules: RuleEntry[]) => { updateField("rules", rules); },
118→    [updateField],
119→  );
120→
121→  const handleClose = useCallback(() => {
122→    if (isSubmitting) return;
123→    setForm(createInitialFormState());
124→    setErrors({});
125→    onClose();
126→  }, [isSubmitting, onClose]);
127→
128→  const handleSubmit = useCallback(async () => {
129→    const validationErrors = validateForm(form);
130→    if (hasErrors(validationErrors)) { setErrors(validationErrors); return; }
131→    if (!workspaceId) return;
132→
133→    setIsSubmitting(true);
134→    setErrors({});
135→
136→    try {
137→      const url = `/api/workspaces/${encodeURIComponent(workspaceId)}/policies`;
138→      const response = await fetch(url, {
139→        method: "POST",
140→        headers: { "Content-Type": "application/json" },
141→        body: JSON.stringify(buildRequestBody(form)),
142→      });
143→
144→      if (!response.ok) {
145→        const text = await response.text();
146→        let message: string;
147→        try {
148→          const parsed = JSON.parse(text) as { error?: string };
149→          message = parsed.error ?? text;
150→        } catch { message = text; }
151→        setErrors({ submit: message || "Failed to create policy" });
152→        return;
153→      }
154→
155→      const data = (await response.json()) as { policy_id: string };
156→      setForm(createInitialFormState());
157→      setErrors({});
158→      onClose();
159→      void navigate({ to: "/policies/$policyId", params: { policyId: data.policy_id } });
160→    } catch (err) {
161→      setErrors({ submit: err instanceof Error ? err.message : "Failed to create policy" });
162→    } finally {
163→      setIsSubmitting(false);
164→    }
165→  }, [form, workspaceId, onClose, navigate]);
166→
167→  return (
168→    <Dialog open={open} onOpenChange={(o) => { if (!o) handleClose(); }}>
169→      <DialogContent className="sm:max-w-lg">
170→        <DialogHeader>
171→          <DialogTitle>Create Policy</DialogTitle>
172→        </DialogHeader>
173→
174→        <div className="flex flex-col gap-3">
175→          {errors.submit && (
176→            <p className="text-sm text-destructive">{errors.submit}</p>
177→          )}
178→
179→          <div className="flex flex-col gap-1.5">
180→            <Label htmlFor="policy-title">Title <span className="text-destructive">*</span></Label>
181→            <Input
182→              id="policy-title"
183→              placeholder="e.g. Restrict code deployment"
184→              value={form.title}
185→              onChange={(e) => updateField("title", e.target.value)}
186→            />
187→            {errors.title && <p className="text-xs text-destructive">{errors.title}</p>}
188→          </div>
189→
190→          <div className="flex flex-col gap-1.5">
191→            <Label htmlFor="policy-description">Description <span className="text-destructive">*</span></Label>
192→            <Textarea
193→              id="policy-description"
194→              placeholder="Describe what this policy governs"
195→              rows={3}
196→              value={form.description}
197→              onChange={(e) => updateField("description", e.target.value)}
198→            />
199→            {errors.description && <p className="text-xs text-destructive">{errors.description}</p>}
200→          </div>
201→
202→          <div className="grid grid-cols-2 gap-3">
203→            <div className="flex flex-col gap-1.5">
204→              <Label htmlFor="policy-agent-role">Agent Role</Label>
205→              <Input
206→                id="policy-agent-role"
207→                placeholder="e.g. coding_agent"
208→                value={form.agentRole}
209→                onChange={(e) => updateField("agentRole", e.target.value)}
210→              />
211→            </div>
212→            <div className="flex flex-col gap-1.5">
213→              <Label htmlFor="policy-max-ttl">Max TTL</Label>
214→              <Input
215→                id="policy-max-ttl"
216→                placeholder="e.g. 1h, 30m"
217→                value={form.maxTtl}
218→                onChange={(e) => updateField("maxTtl", e.target.value)}
219→              />
220→            </div>
221→          </div>
222→
223→          <label className="flex items-center gap-2 text-sm">
224→            <input
225→              type="checkbox"
226→              className="rounded border-input"
227→              checked={form.humanVetoRequired}
228→              onChange={(e) => updateField("humanVetoRequired", e.target.checked)}
229→            />
230→            Human veto required
231→          </label>
232→
233→          <div className="flex flex-col gap-1.5">
234→            <RuleBuilder rules={form.rules} onRulesChange={handleRulesChange} />
235→            {errors.rules && <p className="text-xs text-destructive">{errors.rules}</p>}
236→          </div>
237→        </div>
238→
239→        <DialogFooter>
240→          <Button variant="outline" onClick={handleClose} disabled={isSubmitting}>
241→            Cancel
242→          </Button>
243→          <Button onClick={handleSubmit} disabled={isSubmitting}>
244→            {isSubmitting ? "Creating..." : "Create Policy"}
245→          </Button>
246→        </DialogFooter>
247→      </DialogContent>
248→    </Dialog>
249→  );
250→}
