 2→import { useWorkspaceState } from "../stores/workspace-state";
 3→
 4→export type PolicyStatus = "draft" | "testing" | "active" | "deprecated" | "superseded";
 5→
 6→export type PolicyListItem = {
 7→  id: string;
 8→  title: string;
 9→  status: PolicyStatus;
10→  version: number;
11→  rules_count: number;
12→  human_veto_required: boolean;
13→  created_at: string;
14→  updated_at?: string;
15→};
16→
17→export type PolicyFilters = {
18→  status?: PolicyStatus;
19→};
20→
21→type UsePoliciesReturn = {
22→  policies: PolicyListItem[];
23→  isLoading: boolean;
24→  error?: string;
25→  filters: PolicyFilters;
26→  setFilters: (filters: PolicyFilters) => void;
27→  refresh: () => void;
28→};
29→
30→/** Pure function: builds the API URL for fetching policies with optional status filter. */
31→export function buildPoliciesUrl(workspaceId: string, filters: PolicyFilters): string {
32→  const base = `/api/workspaces/${encodeURIComponent(workspaceId)}/policies`;
33→  const params = new URLSearchParams();
34→
35→  if (filters.status) params.set("status", filters.status);
36→
37→  const query = params.toString();
38→  return query ? `${base}?${query}` : base;
39→}
40→
41→export function usePolicies(): UsePoliciesReturn {
42→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
43→  const [policies, setPolicies] = useState<PolicyListItem[]>([]);
44→  const [isLoading, setIsLoading] = useState(false);
45→  const [error, setError] = useState<string | undefined>();
46→  const [filters, setFilters] = useState<PolicyFilters>({});
47→
48→  const fetchPolicies = useCallback(async () => {
49→    if (!workspaceId) return;
50→
51→    setIsLoading(true);
52→    setError(undefined);
53→
54→    try {
55→      const url = buildPoliciesUrl(workspaceId, filters);
56→      const response = await fetch(url);
57→      if (!response.ok) {
58→        const body = await response.text();
59→        throw new Error(body);
60→      }
61→      const data = (await response.json()) as { policies: PolicyListItem[] };
62→      setPolicies(data.policies);
63→    } catch (err) {
64→      setError(err instanceof Error ? err.message : "Failed to load policies");
65→    } finally {
66→      setIsLoading(false);
67→    }
68→  }, [workspaceId, filters]);
69→
70→  useEffect(() => {
71→    if (!workspaceId) return;
72→    void fetchPolicies();
73→  }, [workspaceId, filters, fetchPolicies]);
74→
75→  const refresh = useCallback(() => {
76→    void fetchPolicies();
77→  }, [fetchPolicies]);
78→
79→  return { policies, isLoading, error, filters, setFilters, refresh };
80→}
