### useLearnings Hook

**File:** `/Users/marcus/conductor/workspaces/brain-v1/lahore-v1/app/src/client/hooks/use-learnings.ts`

```typescript
export function useLearnings(): UseLearningsReturn {
  const workspaceId = useWorkspaceState((s) => s.workspaceId);
  const [learnings, setLearnings] = useState<LearningSummary[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | undefined>();
  const [filters, setFilters] = useState<LearningFilters>({});

  const fetchLearnings = useCallback(async () => {
    if (!workspaceId) return;
    setIsLoading(true);
    setError(undefined);
    try {
      const url = buildLearningsUrl(workspaceId, filters);
      const response = await fetch(url);
      if (!response.ok) throw new Error(await response.text());
      const data = await response.json() as { learnings: LearningSummary[] };
      setLearnings(data.learnings);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to load learnings");
    } finally {
      setIsLoading(false);
    }
  }, [workspaceId, filters]);

  useEffect(() => {
    if (!workspaceId) return;
    void fetchLearnings();
  }, [workspaceId, filters, fetchLearnings]);

  return { learnings, isLoading, error, filters, setFilters, refresh: () => void fetchLearnings() };
}
```

**URL Building:**
```typescript
export function buildLearningsUrl(workspaceId: string, filters: LearningFilters): string {
  const base = `/api/workspaces/${encodeURIComponent(workspaceId)}/learnings`;
  const params = new URLSearchParams();
  if (filters.status) params.set("status", filters.status);
  if (filters.type) params.set("type", filters.type);
  if (filters.agent) params.set("agent", filters.agent);
  return query ? `${base}?${query}` : base;
}
```

### useLearningActions Hook

**File:** `/Users/marcus/conductor/workspaces/brain-v1/lahore-v1/app/src/client/hooks/use-learning-actions.ts`

**Pattern:**
- Returns action functions: `approve`, `dismiss`, `create`, `edit`, `deactivate`
- Each action is a `useCallback` that:
  1. Constructs API URL with workspace ID
  2. Calls `fetch()` with method (POST/PUT)
  3. Returns success boolean (or result object for create)
  4. Handles errors and sets submission state
- Shared `isSubmitting` state to disable buttons during requests

**Sample Action:**
```typescript
const approve = useCallback(
  async (learningId: string) => {
    setIsSubmitting(true);
    try {
      const url = `/api/workspaces/${encodeURIComponent(workspaceId)}/learnings/${encodeURIComponent(learningId)}/approve`;
      const response = await fetch(url, { method: "POST", headers: { "Content-Type": "application/json" } });
      if (!response.ok) throw new Error(await response.text());
      return true;
    } catch (err) {
      console.error("Approve failed:", err);
      return false;
    } finally {
      setIsSubmitting(false);
    }
  },
  [workspaceId]
);
```

